import math

# Per-class prior and per-feature likelihoods P(x_i=1 | y)
priors = {"spam": 0.40, "ham": 0.60}
likelihoods = {
    "spam": {"free": 0.80, "bangs": 0.70},
    "ham": {"free": 0.10, "bangs": 0.05},
}

# Observed email: FREE=1, !!!=1
observed = {"free": 1, "bangs": 1}

def log_score(label: str) -> float:
    score = math.log(priors[label])
    for feat, val in observed.items():
        p1 = likelihoods[label][feat]
        p = p1 if val == 1 else (1 - p1)
        score += math.log(p)
    return score

best = max(priors, key=log_score)
print(best, log_score(best))  # spam, higher log score
